import time
from collections import deque
from functools import wraps
from threading import Lock

class RateLimiter:
    def __init__(self, max_calls, period, strategy='fixed-window'):
        self.max_calls = max_calls
        self.period = period
        self.strategy = strategy
        self.lock = Lock()
        self.calls = 0
        self.start_time = time.time()
        self.call_times = deque()

    def _fixed_window(self):
        current_time = time.time()
        if current_time - self.start_time >= self.period:
            self.start_time = current_time
            self.calls = 0
        if self.calls < self.max_calls:
            self.calls += 1
            return True
        return False

    def _sliding_window(self):
        current_time = time.time()
        while self.call_times and self.call_times[0] <= current_time - self.period:
            self.call_times.popleft()
        if len(self.call_times) < self.max_calls:
            self.call_times.append(current_time)
            return True
        return False

    def is_allowed(self):
        with self.lock:
            if self.strategy == 'fixed-window':
                return self._fixed_window()
            elif self.strategy == 'sliding-window':
                return self._sliding_window()
            else:
                raise ValueError("Invalid strategy. Use 'fixed-window' or 'sliding-window'.")

def rate_limit(max_calls, period, strategy='fixed-window'):
    limiter = RateLimiter(max_calls, period, strategy)

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if limiter.is_allowed():
                return func(*args, **kwargs)
            else:
                raise Exception("Rate limit exceeded")
        return wrapper
    return decorator

# Example usage:
