from functools import wraps
from collections import defaultdict, deque

class RateLimiter:
    def __init__(self, max_calls, period, strategy='fixed-window'):
        self.max_calls = max_calls
        self.period = period
        self.strategy = strategy
        self.lock = threading.Lock()
        if strategy == 'fixed-window':
            self.calls = defaultdict(int)
        elif strategy == 'sliding-window':
            self.calls = defaultdict(deque)
        else:
            raise ValueError("Invalid strategy. Use 'fixed-window' or 'sliding-window'.")

    def is_allowed(self, key):
        current_time = time.time()
        with self.lock:
            if self.strategy == 'fixed-window':
                window_start = current_time // self.period
                if self.calls[key] < window_start:
                    self.calls[key] = window_start
                    self.calls[(key, 'count')] = 0
                if self.calls[(key, 'count')] < self.max_calls:
                    self.calls[(key, 'count')] += 1
                    return True
                return False

            elif self.strategy == 'sliding-window':
                window = self.calls[key]
                while window and window[0] <= current_time - self.period:
                    window.popleft()
                if len(window) < self.max_calls:
                    window.append(current_time)
                    return True
                return False

    def __call__(self, func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = func.__name__
            if self.is_allowed(key):
                return func(*args, **kwargs)
            else:
                raise Exception("Rate limit exceeded.")
        return wrapper

