from collections import defaultdict, deque

class RateLimitException(Exception):
    pass

class RateLimiter:
    def __init__(self, max_calls, period, strategy='fixed-window'):
        self.max_calls = max_calls
        self.period = period
        self.strategy = strategy
        self.lock = threading.Lock()
        self.calls = defaultdict(lambda: deque() if strategy == 'sliding-window' else 0)
        self.timestamps = defaultdict(deque)

    def __call__(self, func):
        if self.strategy == 'fixed-window':
            return self._fixed_window(func)
        elif self.strategy == 'sliding-window':
            return self._sliding_window(func)
        else:
            raise ValueError(f"Unknown strategy: {self.strategy}")

    def _fixed_window(self, func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = args if args else 'global'
            with self.lock:
                current_time = int(time.time())
                if current_time not in self.timestamps[key]:
                    self.timestamps[key].append(current_time)
                    self.calls[key] = 0

                while self.timestamps[key] and self.timestamps[key][0] <= current_time - self.period:
                    self.timestamps[key].popleft()

                if self.calls[key] < self.max_calls:
                    self.calls[key] += 1
                else:
                    raise RateLimitException("Too many requests in fixed window")

            return func(*args, **kwargs)

        return wrapper

    def _sliding_window(self, func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = args if args else 'global'
            with self.lock:
                current_time = time.time()
                while self.calls[key] and self.calls[key][0] <= current_time - self.period:
                    self.calls[key].popleft()

                if len(self.calls[key]) < self.max_calls:
                    self.calls[key].append(current_time)
                else:
