    pass

class RateLimiter:
    def __init__(self, max_calls, period, strategy='fixed-window'):
        self.max_calls = max_calls
        self.period = period
        self.strategy = strategy
        self.lock = threading.Lock()
        self.calls = defaultdict(lambda: deque() if strategy == 'sliding-window' else 0)
        self.timestamps = defaultdict(deque)

    def _fixed_window(self, key):
        current_time = time.time()
        window_start = int(current_time // self.period)

        with self.lock:
            if self.calls[key] < self.max_calls:
                self.calls[key] += 1
            else:
                raise RateLimitException("Rate limit exceeded")

            # Reset the count if we're in a new window
            if len(self.timestamps[key]) == 0 or window_start != self.timestamps[key][0]:
                self.calls[key] = 1
                self.timestamps[key].clear()
                self.timestamps[key].append(window_start)

    def _sliding_window(self, key):
        current_time = time.time()

        with self.lock:
            # Remove timestamps that are out of the window
            while self.timestamps[key] and self.timestamps[key][0] <= current_time - self.period:
                self.timestamps[key].popleft()

            if len(self.timestamps[key]) < self.max_calls:
                self.timestamps[key].append(current_time)
            else:
                raise RateLimitException("Rate limit exceeded")

    def __call__(self, func):
        @wraps(func)
        def wrapped(*args, **kwargs):
            key = (func.__name__, args, frozenset(kwargs.items()))
            if self.strategy == 'fixed-window':
                self._fixed_window(key)
            elif self.strategy == 'sliding-window':
                self._sliding_window(key)
            else:
                raise ValueError("Invalid strategy. Choose 'fixed-window' or 'sliding-window'.")
