import time
import functools
from collections import defaultdict, deque
from threading import Lock

class RateLimitException(Exception):
    pass

class RateLimiter:
    def __init__(self, max_calls, period, strategy='fixed-window'):
        self.max_calls = max_calls
        self.period = period
        self.strategy = strategy
        self.lock = Lock()
        if strategy == 'fixed-window':
            self.calls = defaultdict(int)
            self.last_reset = defaultdict(lambda: time.time())
        elif strategy == 'sliding-window':
            self.calls = defaultdict(deque)

    def is_allowed(self, key):
        with self.lock:
            current_time = time.time()
            if self.strategy == 'fixed-window':
                if current_time - self.last_reset[key] >= self.period:
                    self.calls[key] = 0
                    self.last_reset[key] = current_time

                if self.calls[key] < self.max_calls:
                    self.calls[key] += 1
                    return True
                else:
                    return False

            elif self.strategy == 'sliding-window':
                while self.calls[key] and self.calls[key][0] <= current_time - self.period:
                    self.calls[key].popleft()

                if len(self.calls[key]) < self.max_calls:
                    self.calls[key].append(current_time)
                    return True
                else:
                    return False

def rate_limiter(max_calls, period, strategy='fixed-window'):
    limiter = RateLimiter(max_calls, period, strategy)

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            key = f'{func.__name__}_{args}_{kwargs}'
            if limiter.is_allowed(key):
                return func(*args, **kwargs)
            else:
                raise RateLimitException(f"Rate limit exceeded for {func.__name__}")

        return wrapper

    return decorator

# Example usage:
@rate_limiter(max_calls=3, period=10, strategy='fixed-window')
def my_function():
    return "Function executed successfully"

if __name__ == "__main__":
    for _ in range(5):
        try:
            print(my_function())
        except RateLimitException as e:
            print(e)
        time.sleep(2)
