import time
import functools
from collections import defaultdict
from threading import Lock

class RateLimiter:
    def __init__(self, limit: int, period: int, window_type: str = "fixed"):
        self.limit = limit
        self.period = period
        self.window_type = window_type
        self.calls = defaultdict(list)
        self.lock = Lock()

    def is_allowed(self, key: str) -> bool:
        current_time = time.time()
        with self.lock:
            if self.window_type == "fixed":
                return self._fixed_window(key, current_time)
            elif self.window_type == "sliding":
                return self._sliding_window(key, current_time)
            else:
                raise ValueError("Invalid window_type. Use 'fixed' or 'sliding'.")

    def _fixed_window(self, key: str, current_time: float) -> bool:
        if key not in self.calls:
            self.calls[key] = []
        self._clean_old_calls(key, current_time)

        if len(self.calls[key]) < self.limit:
            self.calls[key].append(current_time)
            return True
        return False

    def _sliding_window(self, key: str, current_time: float) -> bool:
        if key not in self.calls:
            self.calls[key] = []
        self._clean_old_calls(key, current_time)

        if len(self.calls[key]) < self.limit:
            self.calls[key].append(current_time)
            return True
        return False

    def _clean_old_calls(self, key: str, current_time: float):
        cutoff_time = current_time - self.period
        self.calls[key] = [t for t in self.calls[key] if t > cutoff_time]

    def __call__(self, func):
        @functools.wraps(func)
        def wrapped(*args, **kwargs):
            key = f"{func.__module__}.{func.__name__}"
            if not self.is_allowed(key):
                raise Exception("Rate limit exceeded. Try again later.")
            return func(*args, **kwargs)
        return wrapped


