"""
A Python rate limiter decorator that supports both fixed-window and sliding-window strategies.
Usage:

    @fixed_window_rate_limiter(max_calls=5, period=10)
    def my_func(...):
        ...

    @sliding_window_rate_limiter(max_calls=5, period=10)
    def my_other_func(...):
        ...

If the rate limit is exceeded, RateLimitExceeded is raised.
"""

import time
import threading
import functools


class RateLimitExceeded(Exception):
    """Exception raised when the rate limit is exceeded."""
    pass


class BaseRateLimiter:
    def __init__(self, max_calls, period):
        """
        Args:
            max_calls (int): Maximum number of allowed calls in the given period.
            period (float): Time period in seconds.
        """
        self.max_calls = max_calls
        self.period = period
        self.lock = threading.Lock()

    def __call__(self, func):
        """Decorator call."""
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            self._acquire_slot()
            return func(*args, **kwargs)
        return wrapper

    def _acquire_slot(self):
        """
        Checks if a new call is allowed. Should be implemented by subclasses.
        """
        raise NotImplementedError


class FixedWindowRateLimiter(BaseRateLimiter):
    def __init__(self, max_calls, period):
        super().__init__(max_calls, period)
        # Initialize the window start time and the call count in that window.
        self.window_start = time.time()
        self.call_count = 0

    def _acquire_slot(self):
        with self.lock:
            now = time.time()
            # Check if we are in the same window period.
            if now - self.window_start >= self.period:
                # Reset the window.
                self.window_start = now
                self.call_count = 0

            if self.call_count < self.max_calls:
                self.call_count += 1
            else:
                raise RateLimitExceeded(
                    f"Fixed window rate limit exceeded: {self.max_calls} calls per {self.period} seconds"
                )


class SlidingWindowRateLimiter(BaseRateLimiter):
    def __init__(self, max_calls, period):
        super().__init__(max_calls, period)
        # List to store timestamps of calls.
        self.timestamps = []

    def _acquire_slot(self):
        with self.lock:
            now = time.time()
            # Remove timestamps that are outside the sliding window.
            while self.timestamps and self.timestamps[0] <= now - self.period:
                self.timestamps.pop(0)

            if len(self.timestamps) < self.max_calls:
                self.timestamps.append(now)
            else:
                raise RateLimitExceeded(
                    f"Sliding window rate limit exceeded: {self.max_calls} calls per {self.period} seconds"
                )


def fixed_window_rate_limiter(max_calls, period):
    """
    Decorator factory for fixed-window rate limiting.
    """
    limiter = FixedWindowRateLimiter(max_calls, period)
    return limiter


def sliding_window_rate_limiter(max_calls, period):
    """
    Decorator factory for sliding-window rate limiting.
    """
    limiter = SlidingWindowRateLimiter(max_calls, period)
    return limiter


