  @RateLimiter(calls=5, period=10, strategy="fixed")
  def my_function(...):
      ...

  @RateLimiter(calls=3, period=5, strategy="sliding")
  def another_function(...):
      ...

The decorator will block until a call is allowed.
"""

import time
import threading
import functools


class RateLimiter:
    def __init__(self, calls, period, strategy="fixed"):
        """
        :param calls: Maximum number of calls allowed per period.
        :param period: The time window (in seconds) for the allowed calls.
        :param strategy: "fixed" for fixed-window; "sliding" for sliding-window.
        """
        if strategy not in ("fixed", "sliding"):
            raise ValueError("strategy must be either 'fixed' or 'sliding'")
        self.calls = calls
        self.period = period
        self.strategy = strategy
        self.lock = threading.Lock()
        if self.strategy == "fixed":
            self._window_start = time.monotonic()
            self._call_count = 0
        else:
            # For sliding window, we keep timestamps of calls.
            self._timestamps = []

    def _acquire_fixed(self):
        while True:
            now = time.monotonic()
            with self.lock:
                # Check if we moved into a new window.
                if now - self._window_start >= self.period:
                    self._window_start = now
                    self._call_count = 0
                if self._call_count < self.calls:
                    self._call_count += 1
                    return  # Allowed to proceed.
                else:
                    # Need to wait until the current window expires.
                    sleep_time = self.period - (now - self._window_start)
                    # Ensure a minimum sleep time.
                    if sleep_time < 0.001:
                        sleep_time = 0.001
            time.sleep(sleep_time)

    def _acquire_sliding(self):
        while True:
            now = time.monotonic()
            with self.lock:
                # Remove timestamps that are outside the sliding window.
                while self._timestamps and now - self._timestamps[0] >= self.period:
                    self._timestamps.pop(0)
                if len(self._timestamps) < self.calls:
                    self._timestamps.append(now)
                    return
                else:
                    # Wait until the oldest request falls out of the window.
                    sleep_time = self.period - (now - self._timestamps[0])
                    if sleep_time < 0.001:
                        sleep_time = 0.001
            time.sleep(sleep_time)

    def __call__(self, func):
        @functools.wraps(func)
        def wrapped(*args, **kwargs):
            if self.strategy == "fixed":
                self._acquire_fixed()
            else:
                self._acquire_sliding()
            return func(*args, **kwargs)
        return wrapped


