    pass

class RateLimiter:
    """
    A versatile rate limiter that supports 'fixed' window and 'sliding' window strategies.
    Can be used as a decorator.

    Parameters:
        max_requests (int): Maximum number of requests allowed per period.
        period (float): Time period in seconds.
        strategy (str): Rate-limiting strategy: 'fixed' or 'sliding'.
    """
    def __init__(self, max_requests, period, strategy='fixed'):
        if strategy not in ('fixed', 'sliding'):
            raise ValueError("Strategy must be either 'fixed' or 'sliding'")
        self.max_requests = max_requests
        self.period = period
        self.strategy = strategy
        self.lock = threading.Lock()

        if self.strategy == 'fixed':
            # Initialize the current window (epoch-based)
            self.current_window = int(time.time() // self.period)
            self.request_count = 0
        elif self.strategy == 'sliding':
            # Timestamps of the recent requests
            self.timestamps = []

    def allow_request(self):
        """Determine if a request is allowed under the current rate limit."""
        now = time.time()
        with self.lock:
            if self.strategy == 'fixed':
                current_window = int(now // self.period)
                if current_window > self.current_window:
                    # New window started, reset counter
                    self.current_window = current_window
                    self.request_count = 0
                if self.request_count < self.max_requests:
                    self.request_count += 1
                    return True
                else:
                    return False

            elif self.strategy == 'sliding':
                # Remove timestamps that are older than the sliding window period.
                window_start = now - self.period
                # Efficiently remove old timestamps
                while self.timestamps and self.timestamps[0] <= window_start:
                    self.timestamps.pop(0)
                if len(self.timestamps) < self.max_requests:
                    self.timestamps.append(now)
                    return True
                else:
                    return False

    def __call__(self, func):
        """
        The decorator interface that checks the rate limit before executing the function.
        Raises a RateLimitExceeded exception if the rate limit is exceeded.
        """
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if not self.allow_request():
                raise RateLimitExceeded("Rate limit exceeded")
            return func(*args, **kwargs)
        return wrapper

