        if self.strategy == 'fixed':
            # For fixed-window: track the start of the current window and count.
            self.window_start = time.time()
            self.call_count = 0
        elif self.strategy == 'sliding':
            # For sliding-window: use a deque to store recent call timestamps.
            self.call_timestamps = collections.deque()

    def __call__(self, func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            now = time.time()
            if self.strategy == 'fixed':
                # If we're outside the current window, reset.
                if now - self.window_start >= self.period:
                    self.window_start = now
                    self.call_count = 0
                if self.call_count >= self.max_calls:
                    raise RateLimitExceeded(
