import time
import threading
from collections import deque
from functools import wraps

class RateLimitExceeded(Exception):
    """Exception raised when the rate limit is exceeded."""
    pass

class FixedWindowRateLimiter:
    def __init__(self, limit, per):
        """
        Fixed-window rate limiter.

        limit: maximum allowed calls per window.
        per: window length in seconds.
        """
        self.limit = limit
        self.per = per
        self.counter = 0
        self.window_start = int(time.time() // per) * per
        self.lock = threading.Lock()

    def allow_request(self):
        with self.lock:
            current_time = time.time()
            current_window = int(current_time // self.per) * self.per
            if current_window > self.window_start:
                # Reset the count for the new window.
                self.window_start = current_window
                self.counter = 0

            if self.counter < self.limit:
                self.counter += 1
                return True
            else:
                return False

class SlidingWindowRateLimiter:
    def __init__(self, limit, per):
        """
        Sliding-window rate limiter.

        limit: maximum allowed calls in a rolling window.
        per: length of the rolling window in seconds.
        """
        self.limit = limit
        self.per = per
        self.timestamps = deque()
        self.lock = threading.Lock()

    def allow_request(self):
        with self.lock:
            current_time = time.time()
            # Remove timestamps older than the rolling window.
            while self.timestamps and self.timestamps[0] <= current_time - self.per:
                self.timestamps.popleft()
            if len(self.timestamps) < self.limit:
                self.timestamps.append(current_time)
                return True
            else:
                return False

class RateLimiter:
    def __init__(self, limit, per, strategy='fixed', raise_on_limit_exceeded=True):
        """
        A decorator for rate limiting functions.

        Arguments:
        limit: Maximum allowed calls within the window.
        per: The time window in seconds.
        strategy: "fixed" for fixed-window, "sliding" for sliding-window.
        raise_on_limit_exceeded: When True, raises RateLimitExceeded; otherwise, returns None.
        """
        self.limit = limit
        self.per = per
        self.raise_on_limit_exceeded = raise_on_limit_exceeded

        if strategy == 'fixed':
            self.limiter = FixedWindowRateLimiter(limit, per)
        elif strategy == 'sliding':
            self.limiter = SlidingWindowRateLimiter(limit, per)
        else:
            raise ValueError("Unsupported strategy. Use 'fixed' or 'sliding'.")

    def __call__(self, func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if not self.limiter.allow_request():
                if self.raise_on_limit_exceeded:
                    raise RateLimitExceeded("Rate limit exceeded")
                return None
            return func(*args, **kwargs)
        return wrapper

