import time
import threading
import functools
from collections import deque

class RateLimitExceeded(Exception):
    """Exception raised when the rate limit is exceeded."""
    pass

def rate_limiter(limit, period, strategy='fixed'):
    """
    A decorator factory to enforce rate limiting on a function.

    Parameters:
        limit (int): Maximum allowed calls within the given period.
        period (float): Time window size in seconds.
        strategy (str): Rate limiting algorithm to use. Valid options are:
            - 'fixed': Fixed-window strategy.
            - 'sliding': Sliding-window strategy.

    Usage:
        @rate_limiter(limit=5, period=1, strategy='fixed')
        def my_func(...):
            ...

    Raises:
        RateLimitExceeded: When the function is called more times than allowed.
    """

    if strategy not in ('fixed', 'sliding'):
        raise ValueError(f"Unsupported strategy: {strategy}. Use 'fixed' or 'sliding'.")

    # Shared state for the rate limiter.
    lock = threading.Lock()

    if strategy == 'fixed':
        # For the fixed-window strategy, we track the start of the current window and the count.
        state = {'window_start': time.time(), 'count': 0}
    else:  # sliding window
        # For the sliding-window strategy, we store timestamps of each call.
        state = deque()

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            nonlocal state
            now = time.time()
            with lock:
                if strategy == 'fixed':
                    # Check if we're in a new time window
                    if now - state['window_start'] >= period:
                        state['window_start'] = now
                        state['count'] = 0

                    if state['count'] >= limit:
                        raise RateLimitExceeded("Rate limit exceeded (fixed-window strategy)")
                    state['count'] += 1

                elif strategy == 'sliding':
                    # Remove timestamps that are outside of the current sliding window.
                    while state and now - state[0] >= period:
                        state.popleft()

                    if len(state) >= limit:
                        raise RateLimitExceeded("Rate limit exceeded (sliding-window strategy)")
                    state.append(now)

            return func(*args, **kwargs)
        return wrapper

    return decorator

