import time
import threading
import functools
from collections import deque


class FixedWindowRateLimiter:
    def __init__(self, calls, period):
        """
        calls: Maximum number of calls allowed per period.
        period: Time period in seconds.
        """
        self.calls = calls
        self.period = period
        self.current_window_start = self._get_window_start(time.time())
        self.call_count = 0
        self.lock = threading.Lock()

    def _get_window_start(self, current_time):
        return int(current_time / self.period) * self.period

    def allow_request(self):
        with self.lock:
            current_time = time.time()
            window_start = self._get_window_start(current_time)
            if window_start != self.current_window_start:
                # New fixed window, reset the counter.
                self.current_window_start = window_start
                self.call_count = 0
            if self.call_count < self.calls:
                self.call_count += 1
                return True
            return False


class SlidingWindowRateLimiter:
    def __init__(self, calls, period):
        """
        calls: Maximum number of calls allowed in any period seconds.
        period: Time period in seconds.
        """
        self.calls = calls
        self.period = period
        # Deque to hold timestamps of recent calls
        self.timestamps = deque()
        self.lock = threading.Lock()

    def allow_request(self):
        with self.lock:
            current_time = time.time()
            # Remove timestamps older than the sliding window
            while self.timestamps and self.timestamps[0] <= current_time - self.period:
                self.timestamps.popleft()
            if len(self.timestamps) < self.calls:
                self.timestamps.append(current_time)
                return True
            return False


def rate_limit(calls, period, strategy="fixed"):
    """
    Decorator for rate limiting a function.

    Parameters:
    calls    : Maximum number of calls allowed per period.
    period   : Time period in seconds.
    strategy : "fixed" for fixed-window or "sliding" for sliding-window.
    """
    if strategy not in ("fixed", "sliding"):
        raise ValueError("Unsupported strategy. Choose 'fixed' or 'sliding'.")

    # Depending on strategy, create a limiter instance.
    def decorator(func):
        if strategy == "fixed":
            limiter = FixedWindowRateLimiter(calls, period)
        else:
            limiter = SlidingWindowRateLimiter(calls, period)

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if not limiter.allow_request():
                raise Exception("Rate limit exceeded")
            return func(*args, **kwargs)
        return wrapper
    return decorator


