    pass

class FixedWindowLimiter:
    def __init__(self, max_calls, period):
        """
        Fixed-window rate limiter.

        :param max_calls: Maximum allowed calls per period.
        :param period: Time window in seconds.
        """
        self.max_calls = max_calls
        self.period = period
        self.window_start = time.time()
        self.call_count = 0
        self.lock = threading.Lock()

    def allow(self):
        """
        Check if a call is allowed under the fixed-window strategy.
        Returns True if allowed; False otherwise.
        """
        with self.lock:
            now = time.time()
            # Check if we're in a new window
            if now - self.window_start >= self.period:
                self.window_start = now
                self.call_count = 0

            if self.call_count < self.max_calls:
                self.call_count += 1
                return True
            return False

class SlidingWindowLimiter:
    def __init__(self, max_calls, period):
        """
        Sliding-window rate limiter.

        :param max_calls: Maximum allowed calls per period.
        :param period: The sliding time window in seconds.
        """
        self.max_calls = max_calls
        self.period = period
        self.timestamps = collections.deque()
        self.lock = threading.Lock()

    def allow(self):
        """
        Check if a call is allowed under the sliding-window strategy.
        Returns True if allowed; False otherwise.
        """
        with self.lock:
            now = time.time()
            # Remove timestamps older than the current sliding window
            while self.timestamps and now - self.timestamps[0] > self.period:
                self.timestamps.popleft()

            if len(self.timestamps) < self.max_calls:
                self.timestamps.append(now)
                return True
            return False

def rate_limit(max_calls, period, strategy="fixed"):
    """
    Decorator to rate-limit function calls.

    :param max_calls: Maximum allowed calls within the given period.
    :param period: Duration of the window (in seconds).
    :param strategy: The rate-limiting strategy to use: "fixed" or "sliding".
    """
    # Choose the appropriate limiter based on strategy.
    if strategy.lower() == "fixed":
        limiter = FixedWindowLimiter(max_calls, period)
    elif strategy.lower() == "sliding":
        limiter = SlidingWindowLimiter(max_calls, period)
    else:
        raise ValueError(f"Unknown strategy: {strategy}")

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if limiter.allow():
                return func(*args, **kwargs)
            else:
                raise RateLimitExceeded(f"Rate limit of {max_calls} calls per {period} second(s) exceeded.")
        return wrapper
    return decorator

