from collections import deque
from functools import wraps
from typing import Dict, Any, Callable, Optional


class RateLimitExceeded(Exception):
    """Exception raised when rate limit is exceeded."""
    pass


class RateLimitStrategy(ABC):
    """Abstract base class for rate limiting strategies."""

    @abstractmethod
    def is_allowed(self, key: str) -> bool:
        """Check if the request is allowed for the given key."""
        pass

    @abstractmethod
    def reset(self, key: str) -> None:
        """Reset the rate limit for the given key."""
        pass


class FixedWindowStrategy(RateLimitStrategy):
    """Fixed window rate limiting strategy."""

    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self.windows: Dict[str, Dict[str, Any]] = {}
        self.lock = threading.RLock()

    def is_allowed(self, key: str) -> bool:
        with self.lock:
            current_time = time.time()

            if key not in self.windows:
                self.windows[key] = {
                    'count': 0,
                    'window_start': current_time
                }

            window = self.windows[key]

            # Check if we need to reset the window
            if current_time - window['window_start'] >= self.window_seconds:
                window['count'] = 0
                window['window_start'] = current_time

            # Check if request is allowed
            if window['count'] < self.max_requests:
                window['count'] += 1
                return True

            return False

    def reset(self, key: str) -> None:
        with self.lock:
            if key in self.windows:
                del self.windows[key]


class SlidingWindowStrategy(RateLimitStrategy):
    """Sliding window rate limiting strategy."""

    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self.requests: Dict[str, deque] = {}
        self.lock = threading.RLock()

    def is_allowed(self, key: str) -> bool:
        with self.lock:
            current_time = time.time()

            if key not in self.requests:
                self.requests[key] = deque()

            request_times = self.requests[key]

            # Remove requests outside the sliding window
            cutoff_time = current_time - self.window_seconds
            while request_times and request_times[0] <= cutoff_time:
                request_times.popleft()

            # Check if request is allowed
            if len(request_times) < self.max_requests:
                request_times.append(current_time)
                return True

            return False

    def reset(self, key: str) -> None:
        with self.lock:
            if key in self.requests:
                del self.requests[key]


class RateLimiter:
    """Rate limiter that can use different strategies."""

    def __init__(self, strategy: RateLimitStrategy):
        self.strategy = strategy

    def is_allowed(self, key: str) -> bool:
        """Check if a request is allowed for the given key."""
        return self.strategy.is_allowed(key)

    def reset(self, key: str) -> None:
        """Reset the rate limit for the given key."""
        self.strategy.reset(key)


