               window_seconds: int, 
               strategy: str = 'fixed',
               key_func: Optional[Callable] = None,
               raise_on_limit: bool = True):
    """
    Rate limiting decorator.

    Args:
        max_requests: Maximum number of requests allowed
        window_seconds: Time window in seconds
        strategy: 'fixed' or 'sliding' window strategy
        key_func: Function to generate rate limit key (defaults to function name)
        raise_on_limit: Whether to raise exception or return None when limit exceeded
    """

    # Create strategy instance
    if strategy.lower() == 'fixed':
        strategy_instance = FixedWindowStrategy(max_requests, window_seconds)
    elif strategy.lower() == 'sliding':
        strategy_instance = SlidingWindowStrategy(max_requests, window_seconds)
    else:
        raise ValueError("Strategy must be 'fixed' or 'sliding'")

    rate_limiter = RateLimiter(strategy_instance)

    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Generate rate limit key
            if key_func:
                key = key_func(*args, **kwargs)
            else:
                key = f"{func.__module__}.{func.__name__}"

            # Check rate limit
            if not rate_limiter.is_allowed(key):
                if raise_on_limit:
                    raise RateLimitExceeded(
                        f"Rate limit exceeded for {key}. "
                        f"Max {max_requests} requests per {window_seconds} seconds."
                    )
                else:
                    return None

            return func(*args, **kwargs)

        # Add rate limiter methods to wrapper
        wrapper.reset_rate_limit = lambda key=None: rate_limiter.reset(
            key or f"{func.__module__}.{func.__name__}"
        )
        wrapper.rate_limiter = rate_limiter

        return wrapper

    return decorator


