            key = self.key_func(*args, **kwargs)

            if not self.strategy.is_allowed(key):
                raise RateLimitExceeded(f"Rate limit exceeded for key: {key}")

            return func(*args, **kwargs)

        wrapper.reset = self.strategy.reset
        return wrapper

    def check(self, key: str = 'default') -> bool:
        """Check if a request is allowed without consuming a request."""
        return self.strategy.is_allowed(key)

    def reset(self, key: Optional[str] = None) -> None:
        """Reset the rate limiter."""
        self.strategy.reset(key)


# Convenience functions for creating rate limiters
def fixed_window_limiter(max_requests: int, window_seconds: int, key_func: Optional[Callable] = None) -> RateLimiter:
    """Create a fixed window rate limiter."""
    strategy = FixedWindowStrategy(max_requests, window_seconds)
    return RateLimiter(strategy, key_func)


def sliding_window_limiter(max_requests: int, window_seconds: int, key_func: Optional[Callable] = None) -> RateLimiter:
    """Create a sliding window rate limiter."""
    strategy = SlidingWindowStrategy(max_requests, window_seconds)
    return RateLimiter(strategy, key_func)


# Example usage
if __name__ == "__main__":
    # Example 1: Fixed window rate limiter
    @fixed_window_limiter(max_requests=5, window_seconds=60)
    def api_call():
        return "API response"

    # Example 2: Sliding window rate limiter with custom key function
    def user_key_func(*args, **kwargs):
        return kwargs.get('user_id', 'anonymous')

    @sliding_window_limiter(max_requests=10, window_seconds=60, key_func=user_key_func)
    def user_api_call(user_id: str):
        return f"API response for user {user_id}"

    # Example 3: Manual usage
    limiter = sliding_window_limiter(max_requests=3, window_seconds=10)

    try:
        for i in range(5):
            if limiter.check(f"user_{i % 2}"):
                print(f"Request {i} allowed")
            else:
                print(f"Request {i} rate limited")
            time.sleep(1)
    except RateLimitExceeded as e:
        print(f"Rate limit exceeded: {e}")
```

This implementation provides:

1. **Abstract Strategy Pattern**: `RateLimitStrategy` base class allows for different rate limiting algorithms
2. **Fixed Window Strategy**: Resets counters at fixed intervals
3. **Sliding Window Strategy**: Uses a rolling window that moves with each request
4. **Decorator Support**: Can be used as a function decorator with `@rate_limiter`
5. **Custom Key Functions**: Support for per-user or per-IP rate limiting
6. **Thread Safety**: Uses locks to handle concurrent access
7. **Manual Usage**: Can be used programmatically without decorators
8. **Reset Functionality**: Ability to reset rate limits for specific keys or all keys
9. **Exception Handling**: Raises `RateLimitExceeded` when limits are hit

The rate limiter supports both usage patterns:
- As a decorator: `@fixed_window_limiter(5, 60)`
- As a manual checker: `limiter.check('user_123')`

```python
import time
import threading
from abc import ABC, abstractmethod
from collections import defaultdict, deque
from functools import wraps
from typing import Dict, Any, Callable, Optional


class RateLimitExceeded(Exception):
    """Exception raised when rate limit is exceeded."""
    pass


class RateLimitStrategy(ABC):
    """Abstract base class for rate limiting strategies."""

    @abstractmethod
    def is_allowed(self, key: str) -> bool:
        """Check if the request is allowed for the given key."""
        pass

    @abstractmethod
    def reset(self, key: str) -> None:
        """Reset the rate limit for the given key."""
        pass


class FixedWindowStrategy(RateLimitStrategy):
    """Fixed window rate limiting strategy."""

    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self._windows: Dict[str, Dict[str, Any]] = defaultdict(lambda: {
            'count': 0,
            'window_start': time.time()
        })
        self._lock = threading.RLock()

    def is_allowed(self, key: str) -> bool:
        with self._lock:
            current_time = time.time()
            window = self._windows[key]

            # Check if we need to reset the window
            if current_time - window['window_start'] >= self.window_seconds:
                window['count'] = 0
                window['window_start'] = current_time

            # Check if request is allowed
            if window['count'] < self.max_requests:
                window['count'] += 1
                return True

            return False

    def reset(self, key: str) -> None:
        with self._lock:
            if key in self._windows:
                del self._windows[key]


class SlidingWindowStrategy(RateLimitStrategy):
    """Sliding window rate limiting strategy."""

    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self._windows: Dict[str, deque] = defaultdict(deque)
        self._lock = threading.RLock()

    def is_allowed(self, key: str) -> bool:
        with self._lock:
            current_time = time.time()
            window = self._windows[key]

            # Remove expired timestamps
            while window and current_time - window[0] >= self.window_seconds:
                window.popleft()

            # Check if request is allowed
            if len(window) < self.max_requests:
                window.append(current_time)
                return True

            return False

    def reset(self, key: str) -> None:
        with self._lock:
            if key in self._windows:
                del self._windows[key]


class RateLimiter:
    """Rate limiter that supports multiple strategies."""

    def __init__(self, strategy: RateLimitStrategy, key_func: Optional[Callable] = None):
        self.strategy = strategy
        self.key_func = key_func or (lambda *args, **kwargs: 'default')

    def check_rate_limit(self, *args, **kwargs) -> bool:
        """Check if the rate limit allows the request."""
        key = self.key_func(*args, **kwargs)
        return self.strategy.is_allowed(key)

    def reset_key(self, key: str) -> None:
        """Reset rate limit for a specific key."""
        self.strategy.reset(key)

    def __call__(self, func: Callable) -> Callable:
        """Decorator implementation."""
        @wraps(func)
        def wrapper(*args, **kwargs):
            if not self.check_rate_limit(*args, **kwargs):
                raise RateLimitExceeded(f"Rate limit exceeded for function {func.__name__}")
            return func(*args, **kwargs)
        return wrapper


# Convenience functions for common use cases
def fixed_window_rate_limit(max_requests: int, window_seconds: int, 
                           key_func: Optional[Callable] = None):
    """Decorator for fixed window rate limiting."""
    strategy = FixedWindowStrategy(max_requests, window_seconds)
    return RateLimiter(strategy, key_func)


def sliding_window_rate_limit(max_requests: int, window_seconds: int,
                             key_func: Optional[Callable] = None):
    """Decorator for sliding window rate limiting."""
    strategy = SlidingWindowStrategy(max_requests, window_seconds)
    return RateLimiter(strategy, key_func)


# Example usage and key functions
def user_based_key(user_id: str, *args, **kwargs) -> str:
    """Generate key based on user ID."""
    return f"user:{user_id}"


def ip_based_key(request_ip: str, *args, **kwargs) -> str:
    """Generate key based on IP address."""
    return f"ip:{request_ip}"


def function_based_key(*args, **kwargs) -> str:
    """Generate key based on function arguments."""
    return f"func:{hash(str(args) + str(sorted(kwargs.items())))}"


# Example usage
if __name__ == "__main__":
    # Example 1: Simple fixed window rate limiting
    @fixed_window_rate_limit(max_requests=5, window_seconds=60)
    def api_call():
        return "API response"

    # Example 2: Sliding window with user-based key
    @sliding_window_rate_limit(
        max_requests=10, 
        window_seconds=60,
        key_func=lambda user_id: f"user:{user_id}"
    )
    def user_action(user_id: str):
        return f"Action performed for user {user_id}"

    # Example 3: Manual usage
    strategy = FixedWindowStrategy(max_requests=3, window_seconds=10)
    limiter = RateLimiter(strategy, lambda x: f"manual:{x}")

    # Test the rate limiter
    try:
        for i in range(5):
            if limiter.check_rate_limit("test_key"):
                print(f"Request {i+1} allowed")
            else:
                print(f"Request {i+1} denied - rate limit exceeded")
                break
    except Exception as e:
        print(f"Error: {e}")
